window.__CHAR_DATA_URL = "data:image/png;base64,";
(function(){
  const URL = window.__CHAR_DATA_URL;
  function fix(){ document.querySelectorAll('img').forEach(i => { if (i.src && i.src.endsWith("assets/character.png")) i.src = URL; }); }
  fix();
  if (!window.__charObs) {
    window.__charObs = new MutationObserver(fix);
    if (document.body) window.__charObs.observe(document.body, {childList:true, subtree:true});
    else document.addEventListener("DOMContentLoaded", ()=>{ fix(); window.__charObs.observe(document.body, {childList:true, subtree:true}); });
  }
})();